    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for sensor timeout first */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_set_safe_off(controller);
        output.timed_out = true;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
        return output;
    }

    /* Check for invalid temperature */
    if (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
        return output;
    }

    /* Check for stale sensor data (>1000ms since last valid reading) */
    if (controller->has_valid_sensor && input.kind == CONTROLLER_INPUT_NONE) {
        uint32_t now = input.now_ms;
        int32_t elapsed = 0;

        if (now > controller->last_valid_sensor_ms) {
            elapsed = (int32_t)(now - controller->last_valid_sensor_ms);
        } else {
            elapsed = -(int32_t)(controller->last_valid_sensor_ms - now);
        }

        if ((uint32_t)elapsed >= CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_off(controller);
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
            output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
            return output;
        }
    }

    /* Handle temperature input */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        int temp = input.temperature_c;

        /* Store previous temperature for hysteresis comparison BEFORE updating current temp */
        controller->previous_temperature_c = controller->last_temperature_c;

        controller->has_valid_sensor = true;
        controller->last_temperature_c = temp;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Control policy based on temperature */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* TEMP < 47: Turn heater ON */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* TEMP > 52: Turn heater OFF */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_SAFE_OFF;
        } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* 50 <= TEMP <= 52: Check if temperature is rising */
            bool temp_rising = false;

            /* Compare current temp with previous valid sample */
            if (controller->previous_temperature_c != 0 && controller->has_valid_sensor) {
                if (temp > controller->previous_temperature_c) {
                    temp_rising = true;
                }
            }

            if (temp_rising) {
                /* Temperature is rising: Turn heater OFF early, state = HOLDING */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* Temperature not rising: Hold previous safe actuator state (HOLDING) */
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        } else {
            /* 47 <= TEMP < 50: Hold previous safe actuator state (HOLDING) */
            controller->state = CONTROLLER_STATE_HOLDING;
        }
    }

    /* For NONE input with no timeout, just hold current state */
    if (input.kind == CONTROLLER_INPUT_NONE && controller->has_valid_sensor) {
        /* No action needed - maintain current state */
    } else if (input.kind == CONTROLLER_INPUT_NONE && !controller->has_valid_sensor) {
        /* No valid sensor data, stay in current state but no updates */
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

